template:
const std = @import("std");

pub fn parseStateMachine(commands: []const []const u8) !?[]const u8 {
    var state: ?[]const u8 = null;
    var counter: u32 = 0;

    for (commands) |cmd| {
        if (std.mem.eql(u8, cmd, "START")) {
            if ([[SLOT start_already]]) return error.InvalidTransition;
            state = "READY";
        } else if (std.mem.startsWith(u8, cmd, "PROCESS ")) {
            if (state == null or std.mem.eql(u8, state.?, "SHUTDOWN")) return error.InvalidTransition;
            const arg = [[SLOT arg_slice]];
            const n = [[SLOT parse_int]] catch return error.InvalidCommand;
            if (n == 0 or n > 1000) return error.InvalidCommand;
            if ([[SLOT overflow_check]]) return error.CounterOverflow;
            counter += n;
            state = "RUNNING";
        } else if (std.mem.eql(u8, cmd, "STOP")) {
            if (state == null or !std.mem.eql(u8, state.?, "RUNNING")) return error.InvalidTransition;
            state = "READY";
        } else if (std.mem.eql(u8, cmd, "SHUTDOWN")) {
            if (state == null or !std.mem.eql(u8, state.?, "READY")) return error.InvalidTransition;
            state = null;
        } else {
            return error.InvalidCommand;
        }
    }

    return state;
}
